//! Platform sandboxing implementation.

use crate::policy::SandboxPolicy;
use miette::Result;

#[cfg(target_os = "linux")]
pub mod linux;

pub struct PreparedSandbox {
    #[cfg(target_os = "linux")]
    inner: linux::PreparedSandbox,
}

/// Prepare sandboxing rules that require elevated filesystem access.
///
/// # Errors
///
/// Returns an error if sandbox preparation fails in hard-requirement mode.
#[cfg_attr(not(target_os = "linux"), allow(clippy::unnecessary_wraps))]
pub fn prepare(policy: &SandboxPolicy, workdir: Option<&str>) -> Result<PreparedSandbox> {
    #[cfg(target_os = "linux")]
    {
        Ok(PreparedSandbox {
            inner: linux::prepare(policy, workdir)?,
        })
    }

    #[cfg(not(target_os = "linux"))]
    {
        emit_platform_unavailable();
        let _ = (policy, workdir);
        Ok(PreparedSandbox {})
    }
}

/// Apply sandboxing rules for the current platform.
///
/// # Errors
///
/// Returns an error if the sandbox cannot be applied.
#[cfg_attr(not(target_os = "linux"), allow(clippy::unnecessary_wraps))]
pub fn apply(policy: &SandboxPolicy, workdir: Option<&str>) -> Result<()> {
    prepare(policy, workdir)?.apply_after_privilege_drop(policy)
}

impl PreparedSandbox {
    #[cfg_attr(not(target_os = "linux"), allow(clippy::unnecessary_wraps))]
    pub fn apply_after_privilege_drop(self, policy: &SandboxPolicy) -> Result<()> {
        #[cfg(target_os = "linux")]
        {
            self.inner.apply_after_privilege_drop(policy)
        }

        #[cfg(not(target_os = "linux"))]
        {
            let _ = (self, policy);
            Ok(())
        }
    }
}

