#!/usr/bin/env python3
from pathlib import Path

repo = Path('/workspace/OpenShell')
process = (repo / 'crates/openshell-sandbox/src/process.rs').read_text()
ssh = (repo / 'crates/openshell-sandbox/src/ssh.rs').read_text()
landlock = (repo / 'crates/openshell-sandbox/src/sandbox/linux/landlock.rs').read_text()

failures = []

for needle in ['sandbox::apply(&policy', 'sandbox::apply(policy']:
    if needle in process or needle in ssh:
        failures.append(f'old single-phase call remains: {needle}')

for idx, marker in enumerate(['drop_privileges(&policy)', 'drop_privileges(&policy)'], start=1):
    pos = process.find(marker, 0 if idx == 1 else process.find(marker) + 1)
    if pos == -1:
        failures.append(f'missing process drop_privileges occurrence {idx}')
        continue
    before = process.rfind('sandbox::prepare(policy, workdir)?', 0, pos)
    after = process.find('.apply_after_privilege_drop(&policy)', pos)
    if before == -1:
        failures.append(f'process drop_privileges occurrence {idx} has no prior sandbox::prepare')
    if after == -1:
        failures.append(f'process drop_privileges occurrence {idx} has no later apply_after_privilege_drop')

ssh_prepare_positions = [ssh.find('sandbox::prepare(&policy, workdir.as_deref())'), ssh.rfind('sandbox::prepare(&policy, workdir.as_deref())')]
ssh_drop = ssh.find('drop_privileges(policy)')
ssh_apply_after = ssh.find('.apply_after_privilege_drop(policy)', ssh_drop)
if any(pos == -1 for pos in ssh_prepare_positions) or ssh_prepare_positions[0] == ssh_prepare_positions[1]:
    failures.append('SSH helpers should prepare sandbox in both PTY and no-PTY paths')
if ssh_drop == -1 or not all(pos < ssh_drop for pos in ssh_prepare_positions):
    failures.append('SSH sandbox preparation must happen before drop_privileges')
if ssh_apply_after == -1:
    failures.append('SSH helper must apply prepared sandbox after drop_privileges')

prepare_start = landlock.find('pub fn prepare')
impl_start = landlock.find('impl PreparedLandlock')
report_start = landlock.find('fn report_unavailable')
if prepare_start == -1 or impl_start == -1 or report_start == -1:
    failures.append('Landlock prepare/restrict/report structure is missing')
else:
    prepare_body = landlock[prepare_start:impl_start]
    restrict_body = landlock[impl_start:report_start]
    if 'try_open_path(path, compatibility)' not in prepare_body:
        failures.append('Landlock path FDs are not opened during prepare')
    if 'try_open_path(path, compatibility)' in restrict_body:
        failures.append('Landlock path FDs are still opened during restrict_self')
    if 'ruleset.restrict_self()' not in restrict_body:
        failures.append('Prepared Landlock is not restricted after privilege drop')

if 'OpenShell warning: Landlock filesystem sandbox unavailable' not in landlock:
    failures.append('visible stderr warning for Landlock unavailability is missing')
if 'RulesetStatus::NotEnforced' not in landlock:
    failures.append('NotEnforced restriction status is not surfaced')

if failures:
    print('FIX VERIFICATION FAILED:')
    for failure in failures:
        print(f' - {failure}')
    raise SystemExit(1)

print('FIX VERIFIED: Landlock is prepared before privilege drop and restricted afterward with visible warnings.')
