pub fn apply(policy: &SandboxPolicy, workdir: Option<&str>) -> Result<()> {
    prepare(policy, workdir)?.restrict_self()
}

impl PreparedLandlock {
    pub fn restrict_self(self) -> Result<()> {
        let Self::Active {
            ruleset,
            compatibility,
        } = self
        else {
            return Ok(());
        };

        let result = ruleset.restrict_self().into_diagnostic().and_then(|status| {
            if matches!(status.ruleset, RulesetStatus::NotEnforced) {
                Err(miette::miette!(
                    "Landlock restrict_self completed without enforcing the ruleset: {status:?}"
                ))
            } else {
                Ok(())
            }
        });

        if let Err(err) = result {
            if matches!(compatibility, LandlockCompatibility::BestEffort) {
                report_unavailable(&err);
                return Ok(());
            }
            return Err(err);
        }

        Ok(())
    }
}

fn report_unavailable(err: &miette::Report) {
    eprintln!(
        "OpenShell warning: Landlock filesystem sandbox unavailable: {err}. \
         Running WITHOUT filesystem restrictions. Set landlock.compatibility to \
         'hard_requirement' to make this fatal."
    );
    openshell_ocsf::ocsf_emit!(
        openshell_ocsf::DetectionFindingBuilder::new(crate::ocsf_ctx())
            .activity(openshell_ocsf::ActivityId::Open)
            .severity(openshell_ocsf::SeverityId::High)
            .confidence(openshell_ocsf::ConfidenceId::High)
            .is_alert(true)
            .finding_info(
                openshell_ocsf::FindingInfo::new(
                    "landlock-unavailable",
                    "Landlock Filesystem Sandbox Unavailable",
                )
                .with_desc(&format!(
                    "Running WITHOUT filesystem restrictions: {err}. \
